alter table public.tenants enable row level security;alter table public.tenant_memberships enable row level security;alter table public.assessment_templates enable row level security;alter table public.template_relationship_rules enable row level security;alter table public.competencies enable row level security;alter table public.questionnaires enable row level security;alter table public.questions enable row level security;alter table public.questionnaire_questions enable row level security;alter table public.people enable row level security;alter table public.assessment_cycles enable row level security;alter table public.cycle_participants enable row level security;alter table public.rater_assignments enable row level security;alter table public.responses enable row level security;alter table public.score_snapshots enable row level security;alter table public.participant_result_profiles enable row level security;alter table public.integration_exports enable row level security;alter table public.audit_log enable row level security;create policy templates_tenant_isolation on public.assessment_templates  for all  using (tenant_id = app.current_tenant_id())  with check (tenant_id = app.current_tenant_id());